
import React, { createContext, useContext, useState, useCallback, useMemo, useEffect } from 'react';
import { DARK, AMOLED, LIGHT, SEMANTIC } from './theme';

const ThemeContext = createContext(null);

const THEMES = { dark: DARK, amoled: AMOLED, light: LIGHT };

export function ThemeProvider({ children, storedMode = 'dark', onThemeChange }) {
  const [mode, setMode] = useState(THEMES[storedMode] ? storedMode : 'dark');

  useEffect(() => {
    if (THEMES[storedMode] && storedMode !== mode) {
      setMode(storedMode);
    }
  }, [storedMode]);

  const applyTheme = useCallback((nextMode) => {
    if (!THEMES[nextMode]) return;
    setMode(nextMode);
    onThemeChange?.(nextMode);
  }, [onThemeChange]);

  const cycleTheme = useCallback(() => {
    const nextMode = mode === 'dark' ? 'amoled' : mode === 'amoled' ? 'light' : 'dark';
    applyTheme(nextMode);
  }, [mode, applyTheme]);

  const setTheme = useCallback((m) => {
    applyTheme(m);
  }, [applyTheme]);

  const value = useMemo(() => ({
    mode,
    T: { ...THEMES[mode], ...SEMANTIC, mode },   // T = full token set
    cycleTheme,
    setTheme,
  }), [mode, cycleTheme, setTheme]);

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

export const useTheme = () => {
  const ctx = useContext(ThemeContext);
  if (!ctx) throw new Error('useTheme must be inside ThemeProvider');
  return ctx;
};
